{
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "version": "arkpilot-a2ui/v2",
  "scope": "Headless feature logic for 平安扣 Pinankou. Visual integration (final Pages/Components, HTML→ArkUI) is deferred until design artifacts (.arkpilot/plans/design-alignment.md, page-*.html) arrive.",
  "dataModel": {
    "entities": {
      "SafetyMatter": {
        "fields": {
          "id": "string (local uuid)",
          "title": "string",
          "category": "MatterCategory = equipment | environment | behavior | management | other",
          "priority": "MatterPriority = low | medium | high",
          "description": "string",
          "status": "MatterStatus = open | closed",
          "createdAt": "number (ms)",
          "updatedAt": "number (ms)"
        },
        "persistence": "local preferences JSON array under key 'matters'",
        "lifecycle": "open -> closed (toggled on save/edit)"
      },
      "RiskReport": {
        "fields": {
          "id": "string",
          "title": "string",
          "severity": "RiskSeverity = low | medium | high | critical",
          "location": "string",
          "description": "string",
          "status": "RiskStatus = reported | assigned | fixing | resolved",
          "mediaUri": "string | empty",
          "relatedMatterId": "string | empty",
          "reportedAt": "number (ms)",
          "updatedAt": "number (ms)"
        },
        "persistence": "local preferences JSON array under key 'risks'",
        "lifecycle": "reported -> assigned -> fixing -> resolved"
      },
      "PatrolTask": {
        "fields": {
          "id": "string",
          "name": "string",
          "scheduleDate": "number (ms, start of today when generated)",
          "status": "PatrolStatus = pending | in-progress | completed",
          "checkpoints": "Checkpoint[]"
        },
        "persistence": "local preferences JSON under key 'patrol' (single active today task)"
      },
      "Checkpoint": {
        "fields": {
          "checkpointId": "string",
          "name": "string",
          "clockedAt": "number | 0 (0 = not clocked)",
          "note": "string"
        }
      },
      "EmergencyContact": {
        "fields": {
          "id": "string",
          "name": "string",
          "role": "string",
          "phone": "string",
          "isPriority": "boolean",
          "sortOrder": "number",
          "createdAt": "number (ms)"
        },
        "persistence": "local preferences JSON array under key 'contacts'"
      },
      "RectificationTask": {
        "fields": {
          "id": "string",
          "riskId": "string (may be empty for manual)",
          "title": "string",
          "assignee": "string",
          "deadline": "number (ms)",
          "status": "RectificationStatus = pending | in-progress | completed | overdue",
          "steps": "RectificationStep[]",
          "note": "string",
          "createdAt": "number (ms)",
          "completedAt": "number | 0"
        },
        "persistence": "local preferences JSON array under key 'rectifications'",
        "derivedStatus": "overdue is derived from deadline < now && status != completed"
      },
      "RectificationStep": {
        "fields": {
          "stepId": "string",
          "label": "string",
          "done": "boolean",
          "at": "number | 0"
        }
      }
    },
    "settings": {
      "matterFilterStatus": "string ('all' | MatterStatus)",
      "matterSearchQuery": "string",
      "riskFilterSeverity": "string ('all' | RiskSeverity)",
      "riskFilterStatus": "string ('all' | RiskStatus)",
      "rectificationFilterStatus": "string ('all' | RectificationStatus)",
      "statsPeriod": "string ('7d' | '30d' | 'all')"
    },
    "computed": {
      "summary.openMatters": "count of SafetyMatter where status=open",
      "summary.unresolvedRisks": "count of RiskReport where status!=resolved",
      "summary.todayCheckpoints": "count of Checkpoint not clocked in today's patrol",
      "summary.overdueRectifications": "count of RectificationTask where status!=completed && deadline<now",
      "summary.completionRate": "round(doneCheckpoints / totalCheckpoints * 100) for today's patrol, 0 if none",
      "patrol.progress": "doneCheckpoints / totalCheckpoints (0..1)",
      "stats.riskTotal": "count of risks in period",
      "stats.riskResolved": "count of risks status=resolved in period",
      "stats.patrolCompletion": "completionRate of today's patrol",
      "stats.avgResolutionDays": "avg (updatedAt - reportedAt)/day over resolved risks",
      "stats.riskByCategory": "aggregate via relatedMatterId category or default bucket",
      "stats.trend": "risk counts bucketed by day in period"
    }
  },
  "services": {
    "Persistence": {
      "responsibility": "Wrap @ohos.data.preferences; init(context), getString(key), setString(key,value). All values are JSON strings.",
      "init": "called once from EntryAbility.onWindowStageCreate before UI load"
    },
    "Repository (DataStore singleton)": {
      "responsibility": "Typed in-memory arrays for matters, risks, patrol, contacts, rectifications. Load on init from Persistence, persist on mutation. Expose sync getters + mutator methods. Signal change via AppStorage revision counters (matterRev, riskRev, patrolRev, contactRev, rectificationRev)."
    },
    "StatsService": {
      "responsibility": "Pure functions computing summary + dashboard stats from Repository state. No persistence."
    },
    "PhoneService": {
      "responsibility": "Launch system dialer for a phone number via common.UIAbilityContext.startAbility with Want { action: 'ohos.want.action.dial', uri: 'tel:<phone>' }. No in-app call."
    }
  },
  "stateMachine": {
    "SafetyMatter": { "states": ["open", "closed"], "transitions": ["open->closed", "closed->open (on edit)"] },
    "RiskReport": { "states": ["reported", "assigned", "fixing", "resolved"], "transitions": ["reported->assigned", "assigned->fixing", "fixing->resolved"] },
    "PatrolTask": { "states": ["pending", "in-progress", "completed"], "transitions": ["pending->in-progress (start)", "in-progress->completed (all clocked + complete)"] },
    "Checkpoint": { "states": ["not-clocked", "clocked"], "transitions": ["not-clocked->clocked (clock-checkpoint)"] },
    "RectificationTask": { "states": ["pending", "in-progress", "completed", "overdue"], "transitions": ["pending->in-progress", "in-progress->completed", "any-non-completed->overdue (derived when deadline passes)"] }
  },
  "interactionFlows": [
    {
      "name": "open-matter-form",
      "trigger": "home-add-matter-button / matters-add-button / matter-item edit",
      "steps": ["optionally load existing matter by id", "surface MatterForm sheet", "bind form fields to /forms/matter/*"],
      "saveEvent": "save-matter"
    },
    {
      "name": "save-matter",
      "trigger": "matter-form-save-button",
      "inputs": ["title (required)", "category", "priority", "description"],
      "validation": ["title non-empty"],
      "sideEffects": ["upsert SafetyMatter", "set updatedAt", "persist + bump matterRev"],
      "errorPath": "invalid title -> keep form open, surface message"
    },
    {
      "name": "save-risk",
      "trigger": "risk-form-save-button",
      "inputs": ["title (required)", "severity", "location", "description", "mediaUri"],
      "validation": ["title non-empty"],
      "sideEffects": ["upsert RiskReport status defaults reported", "reportedAt on create", "persist + bump riskRev"],
      "errorPath": "invalid title"
    },
    {
      "name": "save-contact",
      "trigger": "contact-form-save-button",
      "inputs": ["name (required)", "role", "phone (required)", "isPriority"],
      "validation": ["name non-empty", "phone non-empty"],
      "sideEffects": ["upsert EmergencyContact", "sortOrder = max+1", "persist + bump contactRev"]
    },
    {
      "name": "call-contact",
      "trigger": "contact-item-{id}-call-button",
      "steps": ["read phone", "PhoneService.dial(phone)"],
      "errorPath": "empty phone -> no-op"
    },
    {
      "name": "start-patrol",
      "trigger": "patrol-start-button",
      "precondition": "today patrol pending",
      "steps": ["ensure today's PatrolTask exists (generate default checkpoints if absent)", "set status in-progress", "bump patrolRev"]
    },
    {
      "name": "clock-checkpoint",
      "trigger": "patrol-checkpoint-{id}-clock-button",
      "inputs": ["checkpointId", "optional note"],
      "steps": ["set clockedAt=now, store note", "bump patrolRev"],
      "expectedState": "checkpoint clocked; if all clocked, enable complete-patrol"
    },
    {
      "name": "complete-patrol",
      "trigger": "patrol-complete-button",
      "precondition": "all checkpoints clocked",
      "steps": ["set patrol status completed", "bump patrolRev"]
    },
    {
      "name": "advance-rectification",
      "trigger": "rectification-detail-advance-button",
      "inputs": ["rectificationId", "note"],
      "steps": ["advance status one step", "if completing set completedAt", "append/refresh note", "persist + bump rectificationRev"]
    },
    {
      "name": "navigate-stats",
      "trigger": "home-stats-link",
      "steps": ["switch to stats surface under tab-more"]
    },
    {
      "name": "navigate-patrol",
      "trigger": "home-patrol-start-button",
      "steps": ["switch to patrol tab"]
    }
  ],
  "testTargets": [
    "home-add-matter-button",
    "home-report-risk-button",
    "home-patrol-start-button",
    "home-open-matters-count",
    "home-unresolved-risks-count",
    "home-today-checkpoints-count",
    "home-overdue-rectifications-count",
    "home-completion-rate",
    "home-urgent-list",
    "matters-add-button",
    "matters-list",
    "risks-add-button",
    "risks-list",
    "patrol-start-button",
    "patrol-checkpoint-list",
    "patrol-complete-button",
    "contacts-add-button",
    "contacts-list",
    "contact-item-{id}-call-button",
    "rectification-list",
    "rectification-overdue-count",
    "stats-risk-total-count",
    "stats-risk-resolved-count",
    "stats-patrol-completion",
    "matter-form-save-button",
    "risk-form-save-button",
    "contact-form-save-button"
  ],
  "changeRequests": [],
  "headlessScope": {
    "implementedNow": ["model types", "Persistence", "Repository/DataStore", "StatsService", "PhoneService", "AppViewModel event methods", "shell tab contract update (TabTypes/BottomTabBar/Index wiring)"],
    "deferredToVisualIntegration": ["final Pages/Components from HTML", "Theme palette to blue-green safety", "SVG icon assets + SvgIcon variant mapping", "semantic .id() bindings on UI elements", "final build"]
  }
}

